:\"https://woocommerce.com/wp-content/uploads/2012/08/ShipStation-Icon-1.png\";s:5:\"title\";s:11:\"ShipStation\";s:4:\"copy\";s:113:\"Ship your WooCommerce orders with confidence, save on top carriers, and automate your processes with ShipStation.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:57:\"https://woocommerce.com/products/shipstation-integration/\";}i:11;a:8:{s:4:\"slug\";s:44:\"orders-list-empty-body-fedex-shipping-module\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:21:\"fedex-shipping-module\";s:4:\"icon\";s:71:\"https://woocommerce.com/wp-content/uploads/2013/01/woo-FedEx-auxjb7.png\";s:5:\"title\";s:21:\"FedEx Shipping Method\";s:4:\"copy\";s:92:\"Get shipping rates from the FedEx API which handles both domestic and international parcels.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:55:\"https://woocommerce.com/products/fedex-shipping-module/\";}i:12;a:8:{s:4:\"slug\";s:57:\"orders-list-empty-body-woocommerce-distance-rate-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:34:\"woocommerce-distance-rate-shipping\";s:4:\"icon\";s:116:\"https://woocommerce.com/wp-content/uploads/2014/07/WooCommerce_Distance_Rate_Shipping_icon-marketplace-160x160-2.png\";s:5:\"title\";s:34:\"WooCommerce Distance Rate Shipping\";s:4:\"copy\";s:88:\"Easily offer shipping rates based on the distance or total travel time to your customer.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:68:\"https://woocommerce.com/products/woocommerce-distance-rate-shipping/\";}i:13;a:8:{s:4:\"slug\";s:46:\"orders-list-empty-body-easyship-shipping-rates\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:23:\"easyship-shipping-rates\";s:4:\"icon\";s:95:\"https://woocommerce.com/wp-content/uploads/2023/09/Ecwid-Easyship-App-Assets_Logo-instasize.png\";s:5:\"title\";s:8:\"Easyship\";s:4:\"copy\";s:66:\"Simplify shipping with Easyship, the all-in-one shipping platform.\";s:11:\"button-text\";s:10:\"Le