(46, 1, '2026-04-28 16:38:41', '2026-04-28 16:38:41', 'Nishane Hacivat menghadirkan aroma pineapple dan woody yang segar dan elegan. Cocok untuk penggunaan fleksibel dengan kesan premium.\r\n<p data-start=\"6668\" data-end=\"6694\"><strong data-start=\"6668\" data-end=\"6682\">Ketahanan:</strong> 10–12 jam</p>\r\n<p data-start=\"6696\" data-end=\"6714\"><strong data-start=\"6696\" data-end=\"6712\">Cocok Untuk:</strong></p>\r\n\r\n<ul data-start=\"6715\" data-end=\"6776\">\r\n 	<li data-start=\"6715\" data-end=\"6733\">Daily &amp; formal</li>\r\n 	<li data-start=\"6734\" data-end=\"6757\">Pecinta aroma clean</li>\r\n 	<li data-start=\"6758\" data-end=\"6776\">Unisex premium</li>\r\n</ul>', 'Nishane Hacivat Extrait de Parfum', 'Aroma fresh fruity woody yang bersih dan elegan dengan nuansa premium.', 'publish', 'open', 'closed', '', 'nishane-hacivat-extrait-de-parfum', '', '', '2026-05-29 16:24:41', '2026-05-29 16:24:41', '', 0, 'https://parfume.bellonime.site/?post_type=product&#038;p=46', 0, 'product', '', 0),
