(178, 7, '2026-06-19 13:39:21', '2026-06-19 13:39:21', '', '8102839399_86149346564470_1777399259505', '', 'inherit', 'open', 'closed', '', '8102839399_86149346564470_1777399259505', '', '', '2026-06-19 13:39:21', '2026-06-19 13:39:21', '', 177, 'http://localhost/wordpress/wp-content/uploads/2026/06/8102839399_86149346564470_1777399259505.png', 0, 'attachment', 'image/png', 0),
(179, 0, '2026-06-19 14:17:15', '2026-06-19 14:17:15', 'Ya, semua produk parfum di toko kami dijamin 100% original lengkap dengan boks asli atau botol decant steril langsung dari distributor resmi.', 'Apakah parfum yang dijual original?', '', 'publish', 'closed', 'closed', '', 'apakah-parfum-yang-dijual-original', '', '', '2026-06-19 14:17:15', '2026-06-19 14:17:15', '', 0, 'http://parfume.local/faq/apakah-parfum-yang-dijual-original/', 0, 'faq', '', 0),
(180, 0, '2026-06-19 14:17:15', '2026-06-19 14:17:15', 'Daya tahan wangi bervariasi antara 6 hingga 12 jam tergantung pada jenis konsentrasi parfum (EDT/EDP), wewangian dasar yang digunakan (Base Notes), serta tingkat aktivitas harian Anda.', 'Berapa lama daya tahan wangi parfum?', '', 'publish', 'closed', 'closed', '', 'berapa-lama-daya-tahan-wangi-parfum', '', '', '2026-06-19 14:17:15', '2026-06-19 14:17:15', '', 0, 'http://parfume.local/faq/berapa-lama-daya-tahan-wangi-parfum/', 0, 'faq', '', 0),
(181, 0, '2026-06-19 14:17:15', '2026-06-19 14:17:15', 'Untuk produk Pre-Order, Anda dapat melakukan pemesanan terlebih dahulu dan pesanan akan ditahan (On Hold) hingga stok siap dikirimkan sesuai dengan estimasi tanggal ready.', 'Bagaimana sistem Pre-Order bekerja?', '', 'publish', 'closed', 'closed', '', 'bagaimana-sistem-pre-order-bekerja', '', '', '2026-06-19 14:17:15', '2026-06-19 14:17:15', '', 0, 'http://parfume.local/faq/bagaimana-sistem-pre-order-bekerja/', 0, 'faq', '', 0),
(182, 0, '2026-06-19 14:17:15', '2026-06-19 14:17:15', 'Ya! Kami memiliki layanan garansi klaim pecah. Anda cukup membuka detail pesanan di akun Anda dan mengirimkan bukti foto/video unboxing melalui form klaim garansi yang tersedia.', 'Apakah ada garansi jika botol pecah di jalan?', '', 'publish', 'closed', 'closed', '', 'apakah-ada-garansi-jika-botol-pecah-di-jalan', '', '', '2026-06-19 14:17:15', '2026-06-19 14:17:15', '', 0, 'http://parfume.local/faq/apakah-ada-garansi-jika-botol-pecah-di-jalan/', 0, 'faq', '', 0),
(183, 0, '2026-06-19 14:17:15', '2026-06-19 14:17:15', 'Setiap pembelanjaan minimal Rp 500.000, Anda berhak memilih 1x sampel tester parfum gratis ukuran 2ml langsung di halaman Checkout.', 'Bagaimana cara mendapatkan Tester Gratis?', '', 'publish', 'closed', 'closed', '', 'bagaimana-cara-mendapatkan-tester-gratis', '', '', '2026-06-19 14:17:15', '2026-06-19 14:17:15', '', 0, 'http://parfume.local/faq/bagaimana-cara-mendapatkan-tester-gratis/', 0, 'faq', '', 0);
